package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/gorilla/websocket"
)

type Role string

const (
	RoleUser  Role = "user"
	RoleMod   Role = "mod"
	RoleAdmin Role = "admin"
)

type Player struct {
	ID       string
	Username string
	Role     Role
	Conn     *websocket.Conn
	Banned   bool
	mu       sync.Mutex
}

type GameServer struct {
	players    map[string]*Player
	mu         sync.RWMutex
	upgrader   websocket.Upgrader
	bannedIPs  map[string]bool
	bannedMu   sync.RWMutex
}

type Message struct {
	Type     string      `json:"type"`
	Username string      `json:"username"`
	Content  string      `json:"content"`
	Data     interface{} `json:"data,omitempty"`
}

type CommandResult struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

func NewGameServer() *GameServer {
	return &GameServer{
		players:   make(map[string]*Player),
		bannedIPs: make(map[string]bool),
		upgrader: websocket.Upgrader{
			CheckOrigin: func(r *http.Request) bool {
				return true
			},
		},
	}
}

func (gs *GameServer) HandleConnection(w http.ResponseWriter, r *http.Request) {
	username := r.Header.Get("X-Username")
	roleHeader := r.Header.Get("X-Role")
	playerID := r.Header.Get("X-Player-ID")

	if username == "" || playerID == "" {
		http.Error(w, "Missing credentials", http.StatusBadRequest)
		return
	}

	role := Role(strings.ToLower(roleHeader))
	if role == "" {
		role = RoleUser
	}

	clientIP := r.RemoteAddr
	gs.bannedMu.RLock()
	if gs.bannedIPs[clientIP] {
		gs.bannedMu.RUnlock()
		http.Error(w, "You are banned", http.StatusForbidden)
		return
	}
	gs.bannedMu.RUnlock()

	conn, err := gs.upgrader.Upgrade(w, r, nil)
	if err != nil {
		log.Printf("Failed to upgrade connection: %v", err)
		return
	}

	player := &Player{
		ID:       playerID,
		Username: username,
		Role:     role,
		Conn:     conn,
		Banned:   false,
	}

	gs.mu.Lock()
	gs.players[playerID] = player
	gs.mu.Unlock()

	log.Printf("Player %s connected with role %s", username, role)

	gs.broadcastMessage(Message{
		Type:    "system",
		Content: fmt.Sprintf("%s joined the game", username),
	})

	go gs.handlePlayer(player)
}

func (gs *GameServer) handlePlayer(player *Player) {
	defer func() {
		gs.mu.Lock()
		delete(gs.players, player.ID)
		gs.mu.Unlock()
		player.Conn.Close()

		gs.broadcastMessage(Message{
			Type:    "system",
			Content: fmt.Sprintf("%s left the game", player.Username),
		})
	}()

	for {
		var msg Message
		err := player.Conn.ReadJSON(&msg)
		if err != nil {
			log.Printf("Error reading from %s: %v", player.Username, err)
			break
		}

		msg.Username = player.Username

		if strings.HasPrefix(msg.Content, "/") {
			gs.handleCommand(player, msg.Content)
		} else {
			gs.broadcastMessage(msg)
		}
	}
}

func (gs *GameServer) handleCommand(player *Player, command string) {
	parts := strings.Fields(command)
	if len(parts) == 0 {
		return
	}

	cmd := strings.ToLower(parts[0])

	switch cmd {
	case "/kick":
		if len(parts) < 2 {
			gs.sendToPlayer(player, Message{
				Type:    "error",
				Content: "Usage: /kick <username>",
			})
			return
		}
		gs.kickPlayer(player, parts[1])

	case "/ban":
		if len(parts) < 2 {
			gs.sendToPlayer(player, Message{
				Type:    "error",
				Content: "Usage: /ban <username>",
			})
			return
		}
		gs.banPlayer(player, parts[1])

	case "/giveitems":
		if len(parts) < 3 {
			gs.sendToPlayer(player, Message{
				Type:    "error",
				Content: "Usage: /giveitems <username> <item>",
			})
			return
		}
		gs.giveItems(player, parts[1], strings.Join(parts[2:], " "))

	case "/promote":
		if len(parts) < 3 {
			gs.sendToPlayer(player, Message{
				Type:    "error",
				Content: "Usage: /promote <username> <role>",
			})
			return
		}
		gs.promotePlayer(player, parts[1], parts[2])

	case "/mute":
		if len(parts) < 2 {
			gs.sendToPlayer(player, Message{
				Type:    "error",
				Content: "Usage: /mute <username>",
			})
			return
		}
		gs.mutePlayer(player, parts[1])

	case "/teleport":
		if len(parts) < 4 {
			gs.sendToPlayer(player, Message{
				Type:    "error",
				Content: "Usage: /teleport <username> <x> <y>",
			})
			return
		}
		gs.teleportPlayer(player, parts[1], parts[2], parts[3])

	default:
		gs.sendToPlayer(player, Message{
			Type:    "error",
			Content: "Unknown command",
		})
	}
}

func (gs *GameServer) kickPlayer(admin *Player, targetUsername string) {
	gs.mu.RLock()
	var target *Player
	for _, p := range gs.players {
		if p.Username == targetUsername {
			target = p
			break
		}
	}
	gs.mu.RUnlock()

	if target == nil {
		gs.sendToPlayer(admin, Message{
			Type:    "error",
			Content: "Player not found",
		})
		return
	}

	gs.sendToPlayer(target, Message{
		Type:    "kicked",
		Content: "You have been kicked by " + admin.Username,
	})

	time.Sleep(100 * time.Millisecond)
	target.Conn.Close()

	gs.broadcastMessage(Message{
		Type:    "system",
		Content: fmt.Sprintf("%s was kicked by %s", targetUsername, admin.Username),
	})

	gs.sendToPlayer(admin, Message{
		Type:    "success",
		Content: fmt.Sprintf("Successfully kicked %s", targetUsername),
	})
}

func (gs *GameServer) banPlayer(admin *Player, targetUsername string) {
	gs.mu.RLock()
	var target *Player
	for _, p := range gs.players {
		if p.Username == targetUsername {
			target = p
			break
		}
	}
	gs.mu.RUnlock()

	if target == nil {
		gs.sendToPlayer(admin, Message{
			Type:    "error",
			Content: "Player not found",
		})
		return
	}

	target.mu.Lock()
	target.Banned = true
	target.mu.Unlock()

	gs.bannedMu.Lock()
	gs.bannedIPs[target.Conn.RemoteAddr().String()] = true
	gs.bannedMu.Unlock()

	gs.sendToPlayer(target, Message{
		Type:    "banned",
		Content: "You have been banned by " + admin.Username,
	})

	time.Sleep(100 * time.Millisecond)
	target.Conn.Close()

	gs.broadcastMessage(Message{
		Type:    "system",
		Content: fmt.Sprintf("%s was banned by %s", targetUsername, admin.Username),
	})

	gs.sendToPlayer(admin, Message{
		Type:    "success",
		Content: fmt.Sprintf("Successfully banned %s", targetUsername),
	})
}

