func (gs *GameServer) promotePlayer(admin *Player, targetUsername string, newRole string) {
	gs.mu.RLock()
	var target *Player
	for _, p := range gs.players {
		if p.Username == targetUsername {
			target = p
			break
		}
	}
	gs.mu.RUnlock()

	if target == nil {
		gs.sendToPlayer(admin, Message{
			Type:    "error",
			Content: "Player not found",
		})
		return
	}

	role := Role(strings.ToLower(newRole))
	if role != RoleUser && role != RoleMod && role != RoleAdmin {
		gs.sendToPlayer(admin, Message{
			Type:    "error",
			Content: "Invalid role. Use: user, mod, or admin",
		})
		return
	}

	target.mu.Lock()
	target.Role = role
	target.mu.Unlock()

	gs.sendToPlayer(target, Message{
		Type:    "role_changed",
		Content: fmt.Sprintf("Your role has been changed to %s by %s", role, admin.Username),
	})

	gs.sendToPlayer(admin, Message{
		Type:    "success",
		Content: fmt.Sprintf("Successfully promoted %s to %s", targetUsername, role),
	})
}

