func (gs *GameServer) sendToPlayer(player *Player, msg Message) {
	player.mu.Lock()
	defer player.mu.Unlock()
	
	err := player.Conn.WriteJSON(msg)
	if err != nil {
		log.Printf("Error sending to %s: %v", player.Username, err)
	}
}

func (gs *GameServer) broadcastMessage(msg Message) {
	gs.mu.RLock()
	defer gs.mu.RUnlock()

	data, _ := json.Marshal(msg)
	for _, player := range gs.players {
		player.mu.Lock()
		player.Conn.WriteMessage(websocket.TextMessage, data)
		player.mu.Unlock()
	}
}

